import styleRegistration from "./Registration.module.scss";
import React, { useCallback } from "react";
import InputText from "./inputText/InputText";
import { useSelector, useDispatch } from "react-redux";
import {
  nickNameActin,
  emailActin,
  passwordActin,
  registerActin,
} from "../../redux/register-reducer.ts";

const Registration = () => {
  const state = useSelector((state) => state.register);
  const dispatch = useDispatch();
  const increaseCounter = useCallback(
    (e, a) => {
      let text = e.target.value;
      dispatch(a(text));
    },
    [dispatch]
  );
  const toButton = () => {
    const { nickName, email, password } = state;
    if (
      nickName === "" ||
      email === "" ||
      password === "" ||
      password.length < 6
    ) {
      return;
    }
    dispatch(registerActin());
  };
  const arr = [
    {
      id: "nickName",
      value: "Nickname",
      placeholder: "Например: Explore23",
      type: "text",
      cr: (e) => increaseCounter(e, nickNameActin),
      valPol: state.nickName,
    },
    {
      id: "email",
      value: "Email",
      placeholder: "Например: explore@gmail.com",
      type: "email",
      cr: (e) => increaseCounter(e, emailActin),
      valPol: state.email,
    },
    {
      id: "password",
      value: "Password",
      placeholder: "Например: 230cd_3rD",
      type: "password",
      cr: (e) => increaseCounter(e, passwordActin),
      valPol: state.password,
    },
  ];

  const formElem = arr.map(({ value, placeholder, id, type, cr, valPol }) => (
    <InputText
      key={id}
      value={value}
      placehold={placeholder}
      id={id}
      type={type}
      createText={cr}
      valPol={valPol}
    />
  ));
  return (
    <form className={styleRegistration.container}>
      <>{formElem}</>
      <button
        type="reset"
        onClick={toButton}
        className={styleRegistration.button}
      >
        Регистрация
      </button>
      <button className={styleRegistration.button}>
        <svg
          xmlns="http://www.w3.org/2000/svg"
          width="16"
          height="16"
          fill="currentColor"
          class="bi bi-box-arrow-in-right"
          viewBox="0 0 16 16"
        >
          <path
            fill-rule="evenodd"
            d="M6 3.5a.5.5 0 0 1 .5-.5h8a.5.5 0 0 1 .5.5v9a.5.5 0 0 1-.5.5h-8a.5.5 0 0 1-.5-.5v-2a.5.5 0 0 0-1 0v2A1.5 1.5 0 0 0 6.5 14h8a1.5 1.5 0 0 0 1.5-1.5v-9A1.5 1.5 0 0 0 14.5 2h-8A1.5 1.5 0 0 0 5 3.5v2a.5.5 0 0 0 1 0v-2z"
          />
          <path
            fill-rule="evenodd"
            d="M11.854 8.354a.5.5 0 0 0 0-.708l-3-3a.5.5 0 1 0-.708.708L10.293 7.5H1.5a.5.5 0 0 0 0 1h8.793l-2.147 2.146a.5.5 0 0 0 .708.708l3-3z"
          />
        </svg>
        <p>войти</p>
      </button>
    </form>
  );
};

export default Registration;
